var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0006-14: <color=#ffd34c>【부록-003】 영상 자료#3</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0006-14：<color=#ffd34c>【付録-003】 映像資料#3</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0006-14: <color=#ffd34c>【Appendix-003】 Video Material 3</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0006-14: <color=#ffd34c>【附錄-003】 影像資料#3</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"스커지 군집이다! 방어선을 넘어오지 못하게 해!","JPN":"スカージの群れだ！防御線を越えさせるな！","ENG":"Horde of Scourges! Don't let them cross the defense line!","TWN":"是災厄群！不要讓它們越過防線！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"너무 많아! 이대론 뚜, 뚫리겠어! 이봐, 도망쳐!","JPN":"あまりにも多すぎる！このままだと、や、やられる！おい、逃げろ！","ENG":"There's just too many! W-we're going to get overrun! Hey, get out of here!","TWN":"太多了！這樣下去會全滅的！喂，快逃啊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"헉...... 헉......","JPN":"はあ……はあ……","ENG":"*Pant* *Pant*","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"으아아아아!!!","JPN":"　","ENG":"AGHHHHH!!!!","TWN":"喝啊啊啊啊！！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"무슨 책을 읽고 있었던 거니?","JPN":"何を読んでるんだ？","ENG":"What book were you reading?","TWN":"妳在讀什麼書？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"나 병실에만 있으면 심심하다고 간호사 언니가 빌려줬어.","JPN":"病室にいると退屈だからって、看護師さんが貸してくれたの。","ENG":"The nice nurse lady gave it to me since it's pretty dull staying in the ward.","TWN":"護士說光待在病房會無聊，所以把書借給了我。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"피터팬이구나...... 읽어보니 어때?","JPN":"ピーターパンか……どうだった？","ENG":"Peter Pan... How did you like it?","TWN":"《彼得潘》……妳讀了覺得怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"응, 모험하는 건 즐거워 보여...... 그런데, 주인공이 참 불쌍하단 생각이 들더라.","JPN":"冒険は楽しそうだけど……主人公はかわいそうかな。","ENG":"It seems really fun to have adventures... But I felt really sorry for the main character.","TWN":"嗯，冒險看起來很有趣……但是，我覺得主人公很可憐。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"왜 그렇게 생각했는데?","JPN":"なぜそう思うんだ？","ENG":"Why is that?","TWN":"為什麼妳會這麼想？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"어른도 될 수 없고, 아빠엄마도 만나지 못하잖아.","JPN":"大人にもなれないし、ママやパパにも会えないから。","ENG":"He can never grow up, and he can never meet his parents either.","TWN":"因為他不能長大，也見不到爸爸媽媽啊。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"나라면 웬디처럼 네버랜드 같은 곳엔 절대로 따라가지 않았을 거야.","JPN":"私だったらウェンディみたいに、ネバーランドのような場所にはついて行かないけど。","ENG":"If I was Wendy, I would never go to a place like Neverland.","TWN":"是我的話，絕對不會像溫蒂一樣跟他去夢幻島。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......그래.","JPN":"……そうか。","ENG":"Yeah.","TWN":"……是啊。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"아빠도 피터팬이 널 그런 이상한 곳에 데려가려고 하면 무슨 수를 써서라도 막을 거다.","JPN":"もしピーターパンがお前をそんな場所へ連れて行こうとしたら、パパがどんな手を使ってでも止めてやる。","ENG":"If Peter Pan tries to take you away to a weird place like that, I would do everything I could to stop him.","TWN":"如果彼得潘想帶妳去那種奇怪的地方，爸爸一定會想盡辦法阻止他的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"어이, 여기 아직 사람이 있다!","JPN":"おい、ここにまだ人がいるぞ！","ENG":"Hey, there's still someone here!","TWN":"喂，這兒還有人呢！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"미치겠군. 그 많은 침식체들을 혼자서 막아내고 있었던 거야? 죽고 싶어 환장했어?","JPN":"ちくしょう。これだけの侵食体を一人で食い止めてたのか？正気じゃないぞ！","ENG":"This is insane. You were defending against all those C.O. by yourself? Are you trying to kill yourself?","TWN":"真是瘋了，一個人要擋下這麼多侵蝕體？你是想死想到瘋了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"헉...... 허억......","JPN":"はあ……はあ……","ENG":"*Pant* *Huff*","TWN":"哈啊……咳咳……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"이, 이봐!","JPN":"お、おい！","ENG":"H-hey!","TWN":"喂，喂！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"어이! 지혈붕대랑 들것 가져와! 빨리!","JPN":"クソ！止血帯と担架を持ってこい！早く！","ENG":"Hey! Bring some bandages and a stretcher! Hurry!","TWN":"喂！把止血繃帶和擔架拿過來！快點！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"으음......? 아빠? 아빠 온 거야?","JPN":"うん……？パパ？パパなの？","ENG":"Hmm? Dad? Are you here dad?","TWN":"嗯……？爸爸？是爸爸來了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......이런. 내가 깨웠나 보구나.","JPN":"……すまん。起こしちゃったみたいだな。","ENG":"Oh. I must have woken you.","TWN":"……真是的，我把妳吵醒了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"으응, 아빠 기다리다가 깜빡 잠들어버렸네. 헤헤.","JPN":"ううん、パパのこと待ってたのに、いつの間にか寝ちゃってた。へへ。","ENG":"Yeah, I fell asleep for a second while waiting for you. Heh.","TWN":"沒有，我在等爸爸的時候睡著了。嘿嘿。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"다시 누우렴. 불 끌게.","JPN":"寝なさい。電気消すから。","ENG":"Lie back down. I'll turn off the light.","TWN":"乖乖躺好，我要關燈了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"아냐, 내가 어떻게 자겠어. 얼마 만에 보는 아빠 얼굴인데.","JPN":"やだ、寝ないもん。せっかく久しぶりにパパに会えたのに。","ENG":"No, I can't sleep now. It's been so long since I saw your face.","TWN":"不要，我不想睡，我好久沒看到爸爸的臉了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"......나 방금 꿈을 꿨어.","JPN":"……私ね、さっき夢を見たの。","ENG":"I just had a dream.","TWN":"……我剛剛做了一個夢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"무슨 꿈?","JPN":"どんな夢だ？","ENG":"What dream?","TWN":"什麼夢？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"남들처럼 교복입고 학교에 가는 꿈. 아빠한테 다녀오겠다고 인사까지 했다?","JPN":"他の子たちみたいに制服を着て学校に行く夢。パパに行ってきますって挨拶もしたんだよ。","ENG":"About going to school in a uniform like everyone else. I even said good bye to you as I headed out the door.","TWN":"像別人一樣穿著校服上學的夢。出門前還跟爸爸說''我出門了''喔。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"나도, 다른 애들처럼 학교에 갈 수 있는 걸까?","JPN":"私も、他の子たちみたいに学校へ行けるかな？","ENG":"Do you think I'll go to school like the other kids?","TWN":"我也能像別的小朋友一樣去上學嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"물론이지.","JPN":"もちろんさ。","ENG":"Of course.","TWN":"當然可以。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그러기 위해서 이렇게 열심히 치료받고 있는 거잖아.","JPN":"そのために頑張って治療を受けてるんだろ？","ENG":"That's why we're all trying our best to help you get better.","TWN":"所以我們才這麼拼命地接受治療啊，不是嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그러니 조금만 더 참아보자.","JPN":"だから、もう少しだけ頑張ろうな。","ENG":"So let's just hang in there for a bit more.","TWN":"所以再忍耐一下吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"다 잘될 거야.","JPN":"きっと良くなるから。","ENG":"Everything will be fine.","TWN":"一切都會好起來的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"깨어났군.","JPN":"目が覚めたか。","ENG":"You're awake.","TWN":"你醒啦。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"여긴......","JPN":"ここは……","ENG":"Where am I?","TWN":"這裡是……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"병원이다. 야전침대에 누워있던 걸 내가 사비 들여서 데려왔지.","JPN":"病院だ。野戦ベッドに横たわっていたのを、俺が自腹で連れてきたんだ。","ENG":"You're at the hospital. I paid for this room for you after finding you in a field bed.","TWN":"這裡是醫院，我把行軍床上的東西都帶過來了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"당신을 발견한 친구가 말하기론, 쑥대밭이 된 채굴장에 혼자서 침식체 시체들을 베개 삼아 자고 있었다던데.","JPN":"発見したやつの話によれば、廃墟になった採掘場で侵食体の死体と一緒に、あんたが一人で倒れてたらしい。","ENG":"According to the guy who found you, you were sleeping alone atop of a pile of C.O. corpses inside a ruined mine.","TWN":"發現你的朋友說，你當時在一個變成廢墟的挖掘場，用侵蝕體的屍體當做枕頭睡覺呢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나 원. 고참이면 고참답게 제 몸 간수는 잘 할 줄 알았더니......","JPN":"ったく。先輩なら先輩らしく、自分の身くらいは守れると思ったのにな……","ENG":"Geez. I thought you were seasoned enough to take care of yourself...","TWN":"真是的，我還以為老手會有老手的樣子，能顧好自己的身體呢……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......고참답지 못하게 굴어서 미안하군.","JPN":"……先輩らしくなくて悪かったな。","ENG":"I'm sorry for not being seasoned enough.","TWN":"……沒有老手的樣子真是抱歉啊。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 병원비가 많이 필요하단 건 알겠지만......","JPN":"おい、治療費がかかるのはわかるが……","ENG":"Hey, I understand that you need lot of money to pay the medical bills...","TWN":"我說，我也知道你需要很多醫療費……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"계속 그러다 일이 잘못 틀어지기라도 하면, 당신 수호천사가 몹시 슬퍼할 거라고.","JPN":"もしもの事があったら、あんたの天使が悲しむぞ。","ENG":"But if you keep pushing yourself and something happens to you, your guardian angel will be very sad.","TWN":"但如果你繼續這樣幹然後出事的話，你的守護天使可是會傷心的啊。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그걸 모르진 않을 텐데?","JPN":"わかってるだろ？","ENG":"I'm sure you know that.","TWN":"這你不是也知道嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......병원비는 이제 필요 없어.","JPN":"……治療費はもういい。","ENG":"I don't have to pay any more medical bills.","TWN":"治療費……現在不需要了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"음? 갑자기 그게 무슨 소리지?","JPN":"は？どういうことだ？","ENG":"Huh? What are you talking about?","TWN":"嗯？你突然在說什麼？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"얼마 전에 퇴원했거든.","JPN":"この間、退院したんだ。","ENG":"She was discharged recently.","TWN":"她前陣子就出院了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"오, 그거 좋은 소식인걸.","JPN":"おお、そりゃあよかった。","ENG":"Oh, that's very good news.","TWN":"哇，那可真是個好消息啊。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 지금쯤이면 그토록 바라던 학교에 가있겠군?","JPN":"この時間なら、ずっと行きたがってた学校にいる頃か？","ENG":"Then I bet she's already attending school like she wanted to?","TWN":"那她現在也去了夢寐以求的學校吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋은 애니까. 친구는 많이 사귀었겠지?","JPN":"いい子だから、きっと友達がたくさんいるんだろうな。","ENG":"Since she's a good kid, she should have plenty of friends now.","TWN":"她是個好孩子，肯定也交了很多朋友吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......글쎄.","JPN":"……どうかな。","ENG":"Who knows.","TWN":"……是吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하하, 이젠 딸이 아버지 병문안을 와야 할 처지라니, 전세가 뒤바뀌었군. 안 그래?","JPN":"はは、今度は娘がパパのお見舞いに来る番か。立場が逆転したな。","ENG":"Hah hah, I guess the tables have turned. Your daughter is going to visit you at the hospital now. Right?","TWN":"哈哈，那現在女兒得來給爸爸探病了，立場反過來了呢，是吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......아아, 말 안 해도 표정을 보니 알겠군. 아이한텐 비밀로 하고 싶단 거지?","JPN":"……ああ、言わなくてもわかる。娘には秘密にしたいんだろ？","ENG":"Ah, I can already tell what you're going to say. You want to keep it a secret from your child?","TWN":"……好啦，你不用說，我看你的表情就知道了。你受傷的事想對孩子保密吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"알겠어. 당신이 이런 꼴로 누워있는 걸 알게 되면 그 애도 힘들어할 테니까.","JPN":"わかったよ。あんたを見たら娘さんも悲しむだろうからな。","ENG":"Fine. She's probably going to blame herself if she finds out that you're lying here.","TWN":"這我懂。要是看到你躺在病床上的模樣，她會很難過吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......이해해줘서 고맙군.","JPN":"……わかってくれて助かるよ。","ENG":"Thank you for understanding.","TWN":"……多謝你能理解。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 몸간수 잘 하라고.","JPN":"じゃあ、お大事にな。","ENG":"Alright, take care of yourself.","TWN":"那你好好照顧身體吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아, 그리고 의사가 퇴원할 때까지 술은 마시지 말라더라.","JPN":"あ、それと退院するまでは禁酒だって医者が言ってたぞ。","ENG":"Oh, and the doctor advised against drinking any alcohol until you're discharged.","TWN":"對了，醫生說在出院之前都不可以喝酒。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"아빠, 또 그 아저씨랑 같이 술 마신 거야?","JPN":"パパ、またあのおじさんとお酒飲んだの？","ENG":"Dad, did you go out for drinks with him again?","TWN":"爸爸，你又跟那個大叔一起喝酒了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"응? 그렇게 티가 많이 나나?","JPN":"うん？よくわかったな？","ENG":"Hmm? Is it that obvious?","TWN":"嗯？有這麼明顯嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"아빠한테서 소독약 냄새 엄청 나거든?","JPN":"すごい消毒液の臭いがするからね。","ENG":"You absolutely reek of disinfectant.","TWN":"爸爸，你知道你身上有一股很濃的消毒水味嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"미, 미안하다. 좀 떨어져있을게.","JPN":"ご、ごめん。少し離れるよ。","ENG":"S-sorry. I'll stay away from you.","TWN":"抱、抱歉，我離遠一點吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"가긴 어딜 가. 이리 와서 손 잡아줘.","JPN":"ダメ。こっち来て、手を握って。","ENG":"Where do you think you're going? Come over here and hold my hand.","TWN":"你要去哪裡，快過來握著我的手呀。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"아무리 술 냄새 풍겨도, 바빠서 자주 보러 못 와도, 아빠는 내가 좋아하는 그 아빠인걸.","JPN":"いくらお酒臭くても、忙しくてなかなか会えなくても、パパは私の大好きなパパだもん。","ENG":"No matter how bad you smell, or how seldom you come visit me, you're still the dad I love.","TWN":"不管你身上酒臭味有多重，就算經常忙得沒時間來看我，爸爸還是那個我最喜歡的爸爸。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......고맙다.","JPN":"……ありがとう。","ENG":"Thanks.","TWN":"……謝謝妳。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"가끔은 술 마셔도 돼.","JPN":"たまにはお酒、飲んでもいいよ。","ENG":"You can go out for a drink sometimes.","TWN":"偶爾喝個酒也沒關係。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"나 보러 자주 못 와도 돼.","JPN":"会いに来れなくても平気だよ。","ENG":"You don't have to come see me every day.","TWN":"不用經常來看我也沒關係。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"그치만, 다치지는 마.","JPN":"だけど、ケガはしないでね。","ENG":"Please, just don't get hurt.","TWN":"但是，不可以受傷。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"아빠가 나처럼 누워있게 되면...... 그땐 정말로 미워할 거니까.","JPN":"パパが私みたいになったら……本当に嫌いになるからね。","ENG":"If you end up in a bed like me... Then I'm really going to hate you.","TWN":"爸爸像我一樣躺著的話……到時候我真的會討厭你的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......그래. 명심할게. 우리 딸.","JPN":"……ああ、わかったよ。","ENG":"Yeah. I'll remember that, Sweetie.","TWN":"……好吧，我會記住的，我的乖女兒。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};